simple.afterForm:
[
    {
        "type": "divider"
    },
    {
        "type": "panel",
        "title": "查询结果",
        "visibleOn": "this.symbol != null",
        "body": [
            {
                "type": "alert",
                "level": "info",
                "body": "当前符号: ${symbol.qualifiedName | default:'-'} (${symbol.kind | default:'-'})"
            },
            {
                "type": "panel",
                "title": "调用者 (Callers)",
                "visibleOn": "this.callers != null && this.callers.length > 0",
                "collapsable": true,
                "body": {
                    "type": "json",
                    "source": "${callers}",
                    "levelExpand": 10
                }
            },
            {
                "type": "panel",
                "title": "被调用者 (Callees)",
                "visibleOn": "this.callees != null && this.callees.length > 0",
                "collapsable": true,
                "body": {
                    "type": "json",
                    "source": "${callees}",
                    "levelExpand": 10
                }
            }
        ]
    }
]
